    class Display
    {
    public:
        explicit Display(TwoWire *twi, EchoController::Controller *controller) : display(128, 64, twi, -1),
                                                                                 controller(controller) {};

        void init();
        void clear();
        void update();
        void print(const char *text);

    private:
        Adafruit_SSD1306 display;
        uint8_t batteryLevel = 0;
        EchoController::Controller *controller{0};

        void repaint();
        void drawSound();
        void drawLight();
        void drawUnits();
        void drawMode();
        void drawBatteryLevel();
        void drawRadiationLevel();
        void drawSplash();
        void drawUptime();

        static void formatFloat(
            char *out,
            size_t outSize,
            float value,
            uint8_t width,
            uint8_t decimals);

        static void formatUptime(
            char *out,
            size_t outSize,
            uint32_t uptimeSecconds);
    }; // namespace Display

